document.addEventListener("DOMContentLoaded",()=>{const hamburger=document.getElementById("hamburger"),mobileMenu=document.getElementById("mobileMenu");hamburger.addEventListener("click",()=>{mobileMenu.classList.toggle("open")}),mobileMenu.querySelectorAll("a").forEach(link=>{link.addEventListener("click",()=>{mobileMenu.classList.remove("open")})}),document.getElementById("currentYear").textContent=(new Date).getFullYear();const blogSwiper=new Swiper(".projects-swiper",{loop:!1,autoplay:{delay:3e3,disableOnInteraction:!0},breakpoints:{0:{slidesPerView:1,spaceBetween:16},768:{slidesPerView:2,spaceBetween:16},992:{slidesPerView:2,spaceBetween:16},1200:{slidesPerView:3,spaceBetween:24}},pagination:{el:".projects-swiper .swiper-pagination",clickable:!0},navigation:{nextEl:".projects-swiper .swiper-button-next",prevEl:".projects-swiper .swiper-button-prev"}})});